type Page = 'dashboard' | 'stock' | 'carParts' | 'suppliers' | 'clients' | 'employees' | 'users' | 'assets' | 'categories' | 'reports' | 'quotes' | 'nfcontrol' | 'workorders' | 'purchaseorders' | 'activitylog';
type Theme = 'light' | 'dark';

const REQUIRED_SQL_SCRIPT = `-- SCRIPT COMPLETO DE INICIALIZAÇÃO (Execute no SQL Editor do Supabase)
-- 1. TABELA DE ORGANIZAÇÕES
CREATE TABLE IF NOT EXISTS public.organizations (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL DEFAULT 'Minha Empresa',
  invite_code text NOT NULL DEFAULT substr(md5(random()::text), 0, 8),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 2. TABELA DE PERFIS
CREATE TABLE IF NOT EXISTS public.profiles (
  id uuid REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
  full_name text,
  role text DEFAULT 'stockist',
  organization_id uuid REFERENCES public.organizations(id)
);

-- 3. TABELA DE CATEGORIAS
CREATE TABLE IF NOT EXISTS public.categories (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 4. TABELA DE PRODUTOS
CREATE TABLE IF NOT EXISTS public.products (
  id text NOT NULL PRIMARY KEY,
  name text NOT NULL,
  quantity numeric DEFAULT 0,
  unit_price numeric DEFAULT 0,
  min_stock numeric DEFAULT 10,
  category_id uuid REFERENCES public.categories(id) ON DELETE SET NULL,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 5. TABELA DE FORNECEDORES
CREATE TABLE IF NOT EXISTS public.suppliers (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL,
  cnpj text UNIQUE NOT NULL,
  contact text,
  address text,
  whatsapp text,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 6. TABELA DE CLIENTES
CREATE TABLE IF NOT EXISTS public.clients (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL,
  cpf text NOT NULL,
  birth_date text,
  email text,
  phone text,
  address text,
  city text,
  state text,
  zip_code text,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 7. TABELA DE FUNCIONÁRIOS
CREATE TABLE IF NOT EXISTS public.employees (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL,
  role text NOT NULL,
  contact text,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 8. TABELA DE MOVIMENTAÇÕES DE ESTOQUE
CREATE TABLE IF NOT EXISTS public.stock_movements (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  product_id text NOT NULL,
  product_name text NOT NULL,
  type text NOT NULL CHECK (type IN ('in', 'out')),
  quantity numeric NOT NULL,
  date timestamp with time zone DEFAULT now() NOT NULL,
  reason text,
  employee_id uuid REFERENCES public.employees(id),
  employee_name text,
  receipt_photo text,
  work_order_id uuid,
  organization_id uuid REFERENCES public.organizations(id)
);

-- 9. TABELA DE NOTAS FISCAIS (NFs)
CREATE TABLE IF NOT EXISTS public.nfs (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  supplier jsonb NOT NULL,
  products jsonb NOT NULL,
  total_value numeric NOT NULL,
  import_date timestamp with time zone DEFAULT now() NOT NULL,
  organization_id uuid REFERENCES public.organizations(id)
);

-- 10. TABELA DE HISTÓRICO DE PREÇOS
CREATE TABLE IF NOT EXISTS public.price_history (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  product_id text NOT NULL,
  price numeric NOT NULL,
  date timestamp with time zone DEFAULT now() NOT NULL,
  organization_id uuid REFERENCES public.organizations(id)
);

-- 11. TABELA DE ATIVOS (PATRIMÔNIO)
CREATE TABLE IF NOT EXISTS public.assets (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL,
  description text,
  value numeric DEFAULT 0,
  location text,
  acquisition_date text,
  photo text,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 12. TABELA DE MANUTENÇÕES
CREATE TABLE IF NOT EXISTS public.maintenance_records (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  asset_id uuid REFERENCES public.assets(id) ON DELETE CASCADE,
  date text NOT NULL,
  description text NOT NULL,
  cost numeric DEFAULT 0,
  type text NOT NULL CHECK (type IN ('completed', 'scheduled')),
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 13. TABELA DE PEÇAS AUTOMOTIVAS
CREATE TABLE IF NOT EXISTS public.car_parts (
  id text NOT NULL PRIMARY KEY,
  name text NOT NULL,
  description text,
  vehicle_model text,
  quantity numeric DEFAULT 0,
  location text,
  photo text,
  unit_price numeric DEFAULT 0,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 14. TABELA DE ORÇAMENTOS
CREATE TABLE IF NOT EXISTS public.quotes (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  title text NOT NULL,
  items jsonb NOT NULL,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 15. TABELA DE ORDENS DE SERVIÇO
CREATE TABLE IF NOT EXISTS public.work_orders (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  title text NOT NULL,
  status text NOT NULL CHECK (status IN ('open', 'in_progress', 'completed')),
  items jsonb NOT NULL,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 16. TABELA DE ORDENS DE COMPRA
CREATE TABLE IF NOT EXISTS public.purchase_orders (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  supplier_id uuid REFERENCES public.suppliers(id),
  supplier_name text NOT NULL,
  status text NOT NULL CHECK (status IN ('pending', 'received')),
  items jsonb NOT NULL,
  organization_id uuid REFERENCES public.organizations(id),
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 17. TABELA DE LOGS
CREATE TABLE IF NOT EXISTS public.activity_logs (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  "user" text NOT NULL,
  action text NOT NULL,
  timestamp timestamp with time zone DEFAULT now() NOT NULL,
  organization_id uuid REFERENCES public.organizations(id)
);

-- 18. TABELA DE NOTIFICAÇÕES
CREATE TABLE IF NOT EXISTS public.notifications (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  message text NOT NULL,
  read boolean DEFAULT false,
  created_at timestamp with time zone DEFAULT now() NOT NULL,
  product_id text,
  organization_id uuid REFERENCES public.organizations(id)
);

-- ATIVAÇÃO DE RLS E POLÍTICAS DE ISOLAMENTO
ALTER TABLE public.organizations ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.products ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.stock_movements ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.suppliers ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.clients ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.employees ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.nfs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.price_history ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.assets ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.maintenance_records ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.car_parts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.quotes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.work_orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.purchase_orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.activity_logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.notifications ENABLE ROW LEVEL SECURITY;

CREATE OR REPLACE FUNCTION public.handle_new_data_organization()
RETURNS TRIGGER AS $$
BEGIN
  NEW.organization_id := (SELECT organization_id FROM public.profiles WHERE id = auth.uid());
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DO $$
DECLARE
    t text;
BEGIN
    FOR t IN SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' AND table_name NOT IN ('organizations', 'profiles')
    LOOP
        EXECUTE format('DROP TRIGGER IF EXISTS set_org_id_%I ON public.%I', t, t);
        EXECUTE format('CREATE TRIGGER set_org_id_%I BEFORE INSERT ON public.%I FOR EACH ROW EXECUTE FUNCTION public.handle_new_data_organization()', t, t);
    END LOOP;
END $$;

DO $$
DECLARE
    t text;
BEGIN
    FOR t IN SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' AND table_name NOT IN ('organizations')
    LOOP
        EXECUTE format('DROP POLICY IF EXISTS "Org isolation" ON public.%I', t);
        EXECUTE format('CREATE POLICY "Org isolation" ON public.%I FOR ALL USING (organization_id = (SELECT organization_id FROM public.profiles WHERE id = auth.uid()))', t);
    END LOOP;
END $$;

DROP POLICY IF EXISTS "Leitura pública de organizações" ON public.organizations;
CREATE POLICY "Leitura pública de organizações" ON public.organizations FOR SELECT USING (true);
DROP POLICY IF EXISTS "Inserção pública de organizações" ON public.organizations;
CREATE POLICY "Inserção pública de organizações" ON public.organizations FOR INSERT WITH CHECK (true);
`;

const AppContent: React.FC = () => {
  const supabase = useSupabase();

  const [session, setSession] = useState<Session | null>(null);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentPage, setCurrentPage] = useState<Page>('dashboard');
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [theme, setTheme] = useState<Theme>('light');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isProfileLoading, setIsProfileLoading] = useState(false);
  const [dbSetupRequired, setDbSetupRequired] = useState(false);
  const [supabaseConfigError, setSupabaseConfigError] = useState<{title: string, message: string, isPaused?: boolean} | null>(null);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [confirmation, setConfirmation] = useState<{
    isOpen: boolean;
    message: string;
    onConfirm: () => void;
  }>({ isOpen: false, message: '', onConfirm: () => {} });

  const addToast = useCallback((message: string, type: ToastMessage['type'] = 'info') => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts(currentToasts => currentToasts.filter(toast => toast.id !== id));
    }, 4000);
  }, []);

  const showConfirmation = useCallback((message: string, onConfirm: () => void) => {
    setConfirmation({ isOpen: true, message, onConfirm: () => {
        onConfirm();
        setConfirmation({ isOpen: false, message: '', onConfirm: () => {} });
    }});
  }, []);

  const closeConfirmation = () => setConfirmation({ isOpen: false, message: '', onConfirm: () => {} });

  useEffect(() => {
    const initSession = async () => {
        try {
            const { data: { session }, error } = await supabase.auth.getSession();
            if (error) {
                console.error("Error retrieving session:", error);
            }
            setSession(session);
        } catch (e: any) {
            console.error("Unexpected error during session init:", e);
            if (e.message?.includes('Failed to fetch')) {
                setSupabaseConfigError({
                    title: "Banco de Dados Adormecido",
                    message: "O Supabase pausou seu projeto por falta de uso nos últimos 7 dias. SEUS DADOS ESTÃO SALVOS! Você só precisa reativá-lo no painel do Supabase para o app voltar a funcionar.",
                    isPaused: true
                });
            }
        }
    };
    initSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      setSession(session);
      if (event === 'SIGNED_OUT') setCurrentUser(null);
    });

    return () => subscription.unsubscribe();
  }, [supabase]);

  useEffect(() => {
    const fetchUserProfile = async () => {
      if (session?.user) {
        setIsProfileLoading(true);
        try {
            const { error: checkError } = await supabase.from('organizations').select('id').limit(1);

            if (checkError) {
                if (checkError.message?.includes('Failed to fetch')) {
                    setSupabaseConfigError({
                        title: "Projeto Pausado pelo Supabase",
                        message: "Não foi possível conectar ao banco de dados. Isso acontece no plano gratuito após 1 semana sem uso. Clique no botão abaixo para ir ao painel do Supabase e clicar em 'Restore' (Restaurar). Seus dados não foram perdidos!",
                        isPaused: true
                    });
                    setIsProfileLoading(false);
                    return;
                }
                if (checkError.code === '42P01') { 
                    setDbSetupRequired(true);
                    setIsProfileLoading(false);
                    return;
                }
            }

            const { data, error } = await supabase
              .from('profiles')
              .select('*')
              .eq('id', session.user.id)
              .single();

            if (data) {
              setCurrentUser({
                id: data.id,
                name: data.full_name,
                email: session.user.email!,
                role: data.role as User['role'],
                organization_id: data.organization_id || undefined,
              });
            } else if (error && error.code === 'PGRST116') {
               const { data: newOrg, error: orgError } = await supabase.from('organizations').insert({ name: 'Minha Empresa' }).select().single();
               if (orgError) throw orgError;

               if (newOrg) {
                   const { data: newProfile, error: profileError } = await supabase.from('profiles').insert({
                       id: session.user.id,
                       full_name: session.user.email?.split('@')[0] || 'Usuário',
                       role: 'admin',
                       organization_id: newOrg.id
                   }).select().single();

                   if (profileError) throw profileError;

                   if (newProfile) {
                        setCurrentUser({
                            id: newProfile.id,
                            name: newProfile.full_name,
                            email: session.user.email!,
                            role: 'admin',
                            organization_id: newOrg.id,
                        });
                   }
               }
            }
        } catch (e: any) {
            console.error("Error loading profile:", e);
            if (e.message?.includes('Failed to fetch')) {
                setSupabaseConfigError({
                    title: "Erro de Conexão",
                    message: "A conexão com o servidor de dados falhou. Verifique se o seu projeto Supabase está ativo.",
                    isPaused: true
                });
            } else {
                addToast("Erro ao conectar com o banco de dados.", "error");
            }
        } finally {
            setIsProfileLoading(false);
        }
      }
    };
    fetchUserProfile();
  }, [session, supabase, addToast]);

  // Notifications Sync
  useEffect(() => {
    if (!currentUser) return;

    const fetchNotifications = async () => {
        const { data, error } = await supabase
            .from('notifications')
            .select('*')
            .order('created_at', { ascending: false })
            .limit(50);

        if (data) {
            setNotifications(data.map(n => ({
                id: n.id,
                message: n.message,
                read: n.read,
                createdAt: n.created_at,
                productId: n.product_id
            })));
        }
    };

    fetchNotifications();

    const channel = supabase.channel('realtime-notifications');
    channel.on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'notifications' }, (payload) => {
        const newNotif: AppNotification = {
            id: payload.new.id,
            message: payload.new.message,
            read: payload.new.read,
            createdAt: payload.new.created_at,
            productId: payload.new.product_id
        };
        setNotifications(prev => [newNotif, ...prev]);
        addToast(`Nova notificação: ${newNotif.message}`, 'info');
    }).on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'notifications' }, (payload) => {
        setNotifications(prev => prev.map(n => n.id === payload.new.id ? { ...n, read: payload.new.read } : n));
    }).subscribe();

    return () => {
        supabase.removeChannel(channel);
    };
  }, [currentUser, supabase, addToast]);

  const addActivityLog = useCallback(async (action: string) => {
    if (!currentUser) return;
    await supabase.from('activity_logs').insert({ user: currentUser.name, action });
  }, [currentUser, supabase]);

  const handleLogout = async () => {
    await addActivityLog('fez logout do sistema.');
    await supabase.auth.signOut();
  };

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as Theme | null;
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    setTheme(savedTheme || (prefersDark ? 'dark' : 'light'));
  }, []);

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove('light', 'dark');
    root.classList.add(theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const renderPage = () => {
    if (!currentUser) return null;
    const commonProps = { addToast, showConfirmation, currentUser, addActivityLog };
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'stock': return <StockControl {...commonProps} />;
      case 'carParts': return <CarParts {...commonProps} />;
      case 'suppliers': return <Suppliers {...commonProps} />;
      case 'clients': return <Clients {...commonProps} />;
      case 'employees': return <Employees {...commonProps} />;
      case 'users': return <Users {...commonProps} />;
      case 'assets': return <Assets {...commonProps} />;
      case 'categories': return <Categories {...commonProps} />;
      case 'nfcontrol': return <NFControl />;
      case 'reports': return <Reports />;
      case 'quotes': return <Quotes {...commonProps} />;
      case 'workorders': return <WorkOrders {...commonProps} />;
      case 'purchaseorders': return <PurchaseOrders {...commonProps} />;
      case 'activitylog': return <ActivityLog />;
      default: return <Dashboard />;
    }
  };

  if (supabaseConfigError) {
      return (
          <div className="flex min-h-screen bg-gray-900 text-white p-4">
              <div className="m-auto w-full max-w-md bg-gray-800 rounded-lg shadow-2xl p-8 border border-yellow-500/50">
                  <div className="flex items-center justify-center w-20 h-20 bg-yellow-900/30 rounded-full mb-6 mx-auto border border-yellow-500 animate-pulse">
                      <svg className="w-10 h-10 text-yellow-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                  </div>
                  <h2 className="text-2xl font-bold text-center text-yellow-400 mb-4">{supabaseConfigError.title}</h2>
                  <p className="text-gray-300 mb-8 text-center leading-relaxed">
                    {supabaseConfigError.message}
                  </p>

                  <div className="space-y-4">
                    <a 
                        href="https://supabase.com/dashboard"
                        target="_blank"
                        rel="noopener noreferrer"
                        className="w-full bg-blue-600 hover:bg-blue-700 py-4 rounded-lg font-bold transition flex items-center justify-center text-lg"
                    >
                        <svg className="w-6 h-6 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                        Ir para o Painel do Supabase
                    </a>

                    <button 
                        onClick={() => window.location.reload()}
                        className="w-full bg-gray-700 hover:bg-gray-600 py-3 rounded-lg font-medium transition"
                    >
                        Já restaurei, recarregar app
                    </button>

                    <button 
                        onClick={() => {
                            localStorage.removeItem('supabaseUrl');
                            localStorage.removeItem('supabaseKey');
                            window.location.reload();
                        }}
                        className="w-full text-gray-500 hover:text-gray-300 text-sm underline transition pt-2"
                    >
                        Configurar novo projeto (Zerar tudo)
                    </button>
                  </div>

                  <div className="mt-8 p-4 bg-blue-900/20 rounded border border-blue-500/30 text-xs text-blue-300 text-center">
                      <p><strong>DICA:</strong> Para evitar que o banco de dados durma, acesse o aplicativo pelo menos uma vez por semana.</p>
                  </div>
              </div>
          </div>
      );
  }

  if (!session) return <Login />;

  if (dbSetupRequired) {
      return (
          <div className="flex min-h-screen bg-gray-900 text-white p-4">
              <div className="m-auto w-full max-w-4xl bg-gray-800 rounded-lg shadow-2xl border border-gray-700">
                  <div className="p-6 bg-red-600 rounded-t-lg">
                      <h2 className="text-2xl font-bold flex items-center">
                          <svg className="w-8 h-8 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
                          Configuração Necessária
                      </h2>
                  </div>
                  <div className="p-8 space-y-6">
                      <p className="text-gray-300">O banco de dados de um novo projeto precisa ser inicializado. Se você já tinha dados em outro projeto, restaure-o no Supabase em vez de criar um novo. Se deseja começar do zero neste novo projeto, execute o script abaixo:</p>
                      <div className="relative">
                          <pre className="bg-black p-4 rounded text-sm text-green-400 font-mono border border-gray-600 max-h-96 overflow-auto">{REQUIRED_SQL_SCRIPT}</pre>
                          <button onClick={() => { navigator.clipboard.writeText(REQUIRED_SQL_SCRIPT); addToast('SQL copiado!', 'success'); }} className="absolute top-2 right-2 bg-blue-600 hover:bg-blue-700 text-white px-3 py-1 rounded text-xs">Copiar</button>
                      </div>
                      <div className="flex justify-end">
                          <button onClick={() => window.location.reload()} className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-lg font-bold">Já executei o SQL, entrar</button>
                      </div>
                  </div>
              </div>
              <ToastContainer toasts={toasts} />
          </div>
      );
  }

  if (isProfileLoading) {
      return (
          <div className="flex h-screen items-center justify-center bg-gray-900">
              <div className="text-center">
                  <svg className="animate-spin h-12 w-12 text-blue-500 mx-auto mb-4" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  <p className="text-blue-400 font-medium">Carregando dados...</p>
              </div>
          </div>
      );
  }

  return (
    <>
      <div className="flex h-screen bg-gray-100 dark:bg-gray-900">
        <Sidebar currentPage={currentPage} setCurrentPage={setCurrentPage} isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} currentUser={currentUser} />
        <div className="flex-1 flex flex-col overflow-hidden">
          <Header theme={theme} setTheme={setTheme} toggleSidebar={() => setIsSidebarOpen(prev => !prev)} notifications={notifications} setNotifications={setNotifications} handleLogout={handleLogout} currentUser={currentUser} />
          <main className="flex-1 overflow-y-auto p-4 sm:p-6 md:p-8">{renderPage()}</main>
        </div>
      </div>
      <ToastContainer toasts={toasts} />
      <ConfirmationModal isOpen={confirmation.isOpen} onClose={closeConfirmation} onConfirm={confirmation.onConfirm} message={confirmation.message} />
    </>
  );
};

const App: React.FC = () => {
  const [supabaseClient, setSupabaseClient] = useState<SupabaseClient<Database> | null>(() => {
    const env = (import.meta as any).env;
    if (env?.VITE_SUPABASE_URL && env?.VITE_SUPABASE_ANON_KEY) {
        try { return createSupabaseClient(); } catch (e) { console.error(e); }
    }
    const url = localStorage.getItem('supabaseUrl');
    const key = localStorage.getItem('supabaseKey');
    if (url && key) {
      try { return createSupabaseClient(url, key); } catch (e) { return null; }
    }
    return null;
  });

  const handleConfigured = () => {
    const url = localStorage.getItem('supabaseUrl');
    const key = localStorage.getItem('supabaseKey');
    if (url && key) {
        try {
            setSupabaseClient(createSupabaseClient(url, key));
        } catch (e) {
            console.error("Failed to create client after configuration", e);
        }
    }
  };

  if (!supabaseClient) return <SupabaseSetup onConfigured={handleConfigured} />;

  return (
    <SupabaseProvider client={supabaseClient}>
      <AppContent />
    </SupabaseProvider>
  );
};

export default App;

import React, { useState, useRef, useMemo, FormEvent, useEffect, useCallback } from 'react';
import { Product, Supplier, StockMovement, ParsedNFe, Employee, PriceHistory, Category, ToastMessage, NFe, WorkOrder, User } from '../types';
import { Table, SortConfig } from './shared/Table';
import { Modal } from './shared/Modal';
import { parseNFeXML } from '../services/nfeParser';
import { parseInvoicePDF } from '../services/geminiService';
import { CameraModal } from './shared/CameraModal';
import { useSupabase } from '../contexts/SupabaseContext';
import { QRCodeScannerModal } from './shared/QRCodeScannerModal';


interface StockControlProps {
  addToast: (message: string, type: ToastMessage['type']) => void;
  showConfirmation: (message: string, onConfirm: () => void) => void;
  addActivityLog: (action: string) => void;
  currentUser: User;
}

export const StockControl: React.FC<StockControlProps> = ({ 
    addToast, showConfirmation, addActivityLog, currentUser
}) => {
  const supabase = useSupabase();

  const [products, setProducts] = useState<Product[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [priceHistory, setPriceHistory] = useState<PriceHistory[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [workOrders, setWorkOrders] = useState<WorkOrder[]>([]);
  const [stockMovements, setStockMovements] = useState<StockMovement[]>([]);

  useEffect(() => {
    const fetchData = async () => {
        const [prodRes, supRes, empRes, priceRes, catRes, woRes, smRes] = await Promise.all([
            supabase.from('products').select('*'),
            supabase.from('suppliers').select('*'),
            supabase.from('employees').select('*'),
            supabase.from('price_history').select('*'),
            supabase.from('categories').select('*'),
            supabase.from('work_orders').select('*'),
            supabase.from('stock_movements').select('*')
        ]);
        if(prodRes.data) setProducts(prodRes.data);
        if(supRes.data) setSuppliers(supRes.data);
        if(empRes.data) setEmployees(empRes.data);
        if(priceRes.data) setPriceHistory(priceRes.data);
        if(catRes.data) setCategories(catRes.data);
        if(woRes.data) setWorkOrders(woRes.data as unknown as WorkOrder[]);
        if(smRes.data) setStockMovements(smRes.data as unknown as StockMovement[]);
    };
    fetchData();

    const channel = supabase.channel('stock-control-db-changes');
    const setupSubscription = (table: string, setter: React.Dispatch<React.SetStateAction<any[]>>) => {
      channel.on('postgres_changes', { event: '*', schema: 'public', table }, (payload) => {
        if (payload.eventType === 'INSERT') {
          setter(current => {
            if (current.some(item => item.id === payload.new.id)) return current;
            return [...current, payload.new as any];
          });
        }
        if (payload.eventType === 'UPDATE') {
          setter(current => current.map(item => item.id === payload.new.id ? payload.new as any : item));
        }
        if (payload.eventType === 'DELETE') {
          setter(current => current.filter(item => item.id !== payload.old.id));
        }
      }).subscribe();
    };

    const tablesToSubscribe = [
        { table: 'products', setter: setProducts },
        { table: 'suppliers', setter: setSuppliers },
        { table: 'employees', setter: setEmployees },
        { table: 'price_history', setter: setPriceHistory },
        { table: 'categories', setter: setCategories },
        { table: 'work_orders', setter: setWorkOrders },
        { table: 'stock_movements', setter: setStockMovements }
    ];
    tablesToSubscribe.forEach(({ table, setter }) => setupSubscription(table, setter));

    return () => {
        supabase.removeChannel(channel);
    };

  }, [supabase]);


  const [isNFeModalOpen, setIsNFeModalOpen] = useState(false);
  const [isOutModalOpen, setIsOutModalOpen] = useState(false);
  const [isPriceHistoryModalOpen, setIsPriceHistoryModalOpen] = useState(false);
  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isReceiptModalOpen, setIsReceiptModalOpen] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [isScannerOpen, setIsScannerOpen] = useState(false);

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [currentProduct, setCurrentProduct] = useState<Partial<Product> | null>(null);
  const [receiptData, setReceiptData] = useState({
    productId: '',
    quantity: 1,
    unitPrice: '',
    photo: '',
    photoName: ''
  });

  const [outQuantity, setOutQuantity] = useState<number | string>(1);
  const [outEmployeeId, setOutEmployeeId] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [nfeData, setNfeData] = useState<ParsedNFe | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig<Product> | null>(null);
  const [selectedItems, setSelectedItems] = useState<string[]>([]);
  const [categoryFilter, setCategoryFilter] = useState<string>('');
  const [outWorkOrderId, setOutWorkOrderId] = useState<string>('');

  const checkLowStock = useCallback(async (product: Product, newQuantity: number) => {
    const minStock = product.min_stock || 10;
    if (newQuantity <= minStock) {
        // Verificamos se já existe uma notificação recente não lida para este produto
        const { data: existing } = await supabase
            .from('notifications')
            .select('*')
            .eq('product_id', product.id)
            .eq('read', false)
            .limit(1);

        if (!existing || existing.length === 0) {
            await supabase.from('notifications').insert({
                message: `Estoque Baixo: O produto "${product.name}" atingiu ${newQuantity} unidades (Mínimo: ${minStock}).`,
                product_id: product.id,
                read: false
            });
        }
    }
  }, [supabase]);

  const filteredProducts = useMemo(() => {
    return products.filter(p =>
      (p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      p.id.toLowerCase().includes(searchTerm.toLowerCase())) &&
      (categoryFilter === '' || p.category_id === categoryFilter)
    );
  }, [products, searchTerm, categoryFilter]);

  const requestSort = (key: keyof Product) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
        direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const sortedProducts = useMemo(() => {
      let sortableItems = [...filteredProducts];
      if (sortConfig !== null) {
          sortableItems.sort((a, b) => {
              const valA = a[sortConfig.key];
              const valB = b[sortConfig.key];
              if (typeof valA === 'number' && typeof valB === 'number') {
                  if (valA < valB) return sortConfig.direction === 'ascending' ? -1 : 1;
                  if (valA > valB) return sortConfig.direction === 'ascending' ? 1 : -1;
                  return 0;
              }
              const strA = String(valA).toLowerCase();
              const strB = String(valB).toLowerCase();
              if (strA < strB) return sortConfig.direction === 'ascending' ? -1 : 1;
              if (strA > strB) return sortConfig.direction === 'ascending' ? 1 : -1;
              return 0;
          });
      }
      return sortableItems;
  }, [filteredProducts, sortConfig]);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setIsLoading(true);
      setError(null);
      setNfeData(null);

      if (file.type === 'application/pdf') {
          const reader = new FileReader();
          reader.onload = async (e) => {
              try {
                  const base64 = (e.target?.result as string).split(',')[1];
                  const parsedData = await parseInvoicePDF(base64);
                  setNfeData(parsedData);
              } catch (err) {
                  setError(err instanceof Error ? err.message : 'Erro ao processar PDF com IA');
              } finally {
                  setIsLoading(false);
              }
          };
          reader.readAsDataURL(file);
      } else {
          const reader = new FileReader();
          reader.onload = async (e) => {
              try {
                  const content = e.target?.result as string;
                  const parsedData = await parseNFeXML(content);
                  setNfeData(parsedData);
              } catch (err) {
                  setError(err instanceof Error ? err.message : 'Erro ao processar XML');
              } finally {
                  setIsLoading(false);
              }
          };
          reader.readAsText(file);
      }
    }
  };

  const addStockMovement = useCallback(async (movement: Omit<StockMovement, 'id' | 'date' | 'user_id'>) => {
    const { data, error } = await supabase.from('stock_movements').insert({ ...movement, date: new Date().toISOString() }).select().single();
    if(error) {
        addToast(`Erro ao registrar movimento: ${error.message}`, 'error');
    } else if(data) {
        setStockMovements(prev => [...prev, data as unknown as StockMovement]);
    }
  }, [addToast, supabase]);

  const addNf = useCallback(async (nf: Omit<NFe, 'id' | 'user_id'>) => {
    const { error } = await supabase.from('nfs').insert(nf as any).select().single();
    if(error) {
        addToast(`Erro ao salvar NF: ${error.message}`, 'error');
    }
  }, [addToast, supabase]);


  const confirmNFeImport = async () => {
    if (!nfeData) return;

    let supplier = suppliers.find(s => s.cnpj === nfeData.supplier.cnpj);

    if (!supplier && nfeData.supplier.cnpj) {
        const { data: existingData } = await supabase
            .from('suppliers')
            .select('*')
            .eq('cnpj', nfeData.supplier.cnpj)
            .maybeSingle();

        if (existingData) {
            supplier = existingData;
            if (!suppliers.some(s => s.id === existingData.id)) {
                setSuppliers(prev => [...prev, existingData]);
            }
        } else {
            const { data: newlyCreatedSupplierData, error: insertError } = await supabase
                .from('suppliers')
                .insert({
                    name: nfeData.supplier.name,
                    cnpj: nfeData.supplier.cnpj,
                })
                .select(); 

            if (insertError) {
                addToast(`Erro ao criar novo fornecedor: ${insertError.message}`, 'error');
                return;
            }

            if (newlyCreatedSupplierData && newlyCreatedSupplierData.length > 0) {
                supplier = newlyCreatedSupplierData[0];
                if (supplier) setSuppliers(prev => [...prev, supplier as Supplier]);
            } else {
                 const { data: refetchData } = await supabase.from('suppliers').select('*').eq('cnpj', nfeData.supplier.cnpj).maybeSingle();
                 if(refetchData) {
                     supplier = refetchData;
                     setSuppliers(prev => [...prev, supplier as Supplier]);
                 }
            }
        }
    }

    const consolidatedNfeProducts = new Map<string, { name: string, quantity: number, unit_price: number }>();

    for (const p of nfeData.products) {
        if (consolidatedNfeProducts.has(p.code)) {
            const existing = consolidatedNfeProducts.get(p.code)!;
            consolidatedNfeProducts.set(p.code, {
                ...existing,
                quantity: existing.quantity + p.quantity,
                unit_price: p.unit_price 
            });
        } else {
            consolidatedNfeProducts.set(p.code, { name: p.name, quantity: p.quantity, unit_price: p.unit_price });
        }
    }

    const productsToUpsert = [];
    const movementsToInsert = [];
    const pricesToInsert = [];

    for (const [code, data] of consolidatedNfeProducts.entries()) {
        const existingProduct = products.find(p => p.id === code);
        const newQuantity = (existingProduct ? existingProduct.quantity : 0) + data.quantity;

        productsToUpsert.push({
            id: code,
            name: data.name,
            quantity: newQuantity,
            unit_price: data.unit_price,
        });

        const lastPriceEntry = priceHistory
            .filter(ph => ph.product_id === code)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())[0];

        const lastPrice = lastPriceEntry ? lastPriceEntry.price : (existingProduct ? existingProduct.unit_price : 0);

        if (data.unit_price !== lastPrice) {
            pricesToInsert.push({
                product_id: code,
                price: data.unit_price,
                date: new Date().toISOString(),
            });
        }

        movementsToInsert.push({
            product_id: code,
            product_name: data.name,
            type: 'in' as const,
            quantity: data.quantity,
            reason: `NF-e ${nfeData.supplier.cnpj} (Consolidado)`,
        });
    }

    setProducts(prev => {
        const updated = [...prev];
        productsToUpsert.forEach(upserted => {
            const idx = updated.findIndex(p => p.id === upserted.id);
            if (idx >= 0) updated[idx] = { ...updated[idx], ...upserted };
            else updated.push(upserted as Product);
        });
        return updated;
    });

    const { error: productsError } = await supabase.from('products').upsert(productsToUpsert);
    if (productsError) {
        addToast(`Erro ao atualizar produtos: ${productsError.message}`, 'error');
        return;
    }

    const { data: insertedMovements, error: movementsError } = await supabase.from('stock_movements').insert(movementsToInsert).select();
    if (movementsError) {
        addToast(`Erro ao registrar movimentos: ${movementsError.message}`, 'error');
    } else if (insertedMovements) {
        setStockMovements(prev => [...prev, ...(insertedMovements as unknown as StockMovement[])]);
    }

    if (pricesToInsert.length > 0) {
        const { error: pricesError } = await supabase.from('price_history').insert(pricesToInsert);
        if (pricesError) addToast(`Erro ao salvar histórico de preços: ${pricesError.message}`, 'warning');
    }

    const totalValue = nfeData.products.reduce((acc, prod) => acc + (prod.quantity * prod.unit_price), 0);
    const newNf: Omit<NFe, 'id' | 'user_id'> = {
        supplier: nfeData.supplier,
        products: nfeData.products,
        total_value: totalValue,
        import_date: new Date().toISOString(),
    };
    await addNf(newNf);

    addActivityLog(`importou NF-e de ${nfeData.supplier.name}.`);
    addToast(`${consolidatedNfeProducts.size} tipos de produtos importados com sucesso!`, 'success');
    closeNFeModal();
  };

  const handleProductSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const id = currentProduct?.id ? currentProduct.id : (formData.get('id') as string);

    const productData = {
        id: id,
        name: formData.get('name') as string,
        quantity: parseFloat(formData.get('quantity') as string),
        unit_price: parseFloat(formData.get('unitPrice') as string),
        category_id: formData.get('categoryId') as string || null,
        min_stock: parseFloat(formData.get('minStock') as string) || 0,
    };

    if (!currentProduct?.id && products.some(p => p.id === id)) {
        addToast('Erro: Já existe um produto com este código.', 'error');
        return;
    }

    if (currentProduct?.id) {
        const originalProducts = products;
        setProducts(prev => prev.map(p => p.id === currentProduct.id ? { ...p, ...productData } : p));
        const { error } = await supabase.from('products').update(productData).eq('id', currentProduct.id);
        if (error) {
            addToast(`Erro ao atualizar: ${error.message}`, 'error');
            setProducts(originalProducts);
        } else {
            addToast('Produto atualizado com sucesso!', 'success');
            addActivityLog(`atualizou o produto: ${productData.name}.`);
            // Check for low stock after update
            checkLowStock({ ...originalProducts.find(p => p.id === id), ...productData } as Product, productData.quantity);
        }
    } else {
        const { data, error } = await supabase.from('products').insert(productData).select().single();
        if (error) {
             addToast(`Erro ao criar: ${error.message}`, 'error');
        } else if (data) {
             setProducts(prev => [...prev, data]);
             await addStockMovement({
                product_id: id,
                product_name: productData.name,
                type: 'in',
                quantity: productData.quantity,
                reason: 'Cadastro manual'
            });
            const { error: priceError } = await supabase.from('price_history').insert({
                product_id: id,
                price: productData.unit_price,
                date: new Date().toISOString()
            });
            if (priceError) addToast(`Erro ao salvar preço: ${priceError.message}`, 'warning');
            addToast('Produto cadastrado com sucesso!', 'success');
            addActivityLog(`cadastrou o produto: ${productData.name}.`);
            // Check for low stock after creation
            checkLowStock(data as Product, productData.quantity);
        }
    }

    closeProductModal();
  };

  const handleDeleteProduct = (id: string, name: string) => {
    showConfirmation('Tem certeza que deseja excluir este produto?', async () => {
        const originalProducts = products;
        setProducts(prev => prev.filter(p => p.id !== id));
        const { error } = await supabase.from('products').delete().eq('id', id);
        if (error) {
            addToast(`Erro ao excluir: ${error.message}`, 'error');
            setProducts(originalProducts);
        } else {
            addToast('Produto excluído com sucesso!', 'success');
            addActivityLog(`excluiu o produto: ${name}.`);
        }
    });
  }

  const handleDeleteSelected = () => {
      showConfirmation(`Tem certeza que deseja excluir ${selectedItems.length} produtos?`, async () => {
          const originalProducts = products;
          const selectedNames = products.filter(p => selectedItems.includes(p.id)).map(p => p.name).join(', ');
          setProducts(prev => prev.filter(p => !selectedItems.includes(p.id)));
          const { error } = await supabase.from('products').delete().in('id', selectedItems);
          if (error) {
               addToast(`Erro ao excluir: ${error.message}`, 'error');
               setProducts(originalProducts);
          } else {
            addToast(`${selectedItems.length} produtos excluídos com sucesso!`, 'success');
            addActivityLog(`excluiu ${selectedItems.length} produtos: ${selectedNames}.`);
            setSelectedItems([]);
          }
      });
  }

  const handleReceiptPhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onloadend = () => {
            setReceiptData(prev => ({ ...prev, photo: reader.result as string, photoName: file.name }));
        };
        reader.readAsDataURL(file);
    }
  };

   const handleCameraCapture = (imageData: string) => {
    setReceiptData(prev => ({ ...prev, photo: imageData, photoName: `captura_${Date.now()}.jpg` }));
    setIsCameraModalOpen(false);
  };

  const handleReceiptSubmit = async (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const { productId, quantity, unitPrice, photo } = receiptData;
    const product = products.find(p => p.id === productId);

    if (!product || quantity <= 0) {
        addToast("Produto ou quantidade inválida.", "error");
        return;
    }

    const newQuantity = product.quantity + quantity;
    const newPrice = unitPrice ? parseFloat(unitPrice) : product.unit_price;

    const originalProducts = products;
    setProducts(prev => prev.map(p => p.id === productId ? { ...p, quantity: newQuantity, unit_price: newPrice } : p));

    const { error: updateError } = await supabase
        .from('products')
        .update({ quantity: newQuantity, unit_price: newPrice })
        .eq('id', productId);

    if (updateError) {
        addToast(`Erro ao atualizar produto: ${updateError.message}`, 'error');
        setProducts(originalProducts);
        return;
    }

    await addStockMovement({
        product_id: product.id,
        product_name: product.name,
        type: 'in',
        quantity: quantity,
        reason: 'Entrada avulsa com comprovante',
        receipt_photo: photo
    });

    if (unitPrice) {
        const { error: priceError } = await supabase.from('price_history').insert({
            product_id: product.id,
            price: parseFloat(unitPrice),
            date: new Date().toISOString()
        });
        if (priceError) addToast(`Erro ao salvar histórico de preço: ${priceError.message}`, 'warning');
    }

    addToast("Entrada avulsa registrada com sucesso!", "success");
    addActivityLog(`registrou entrada avulsa de ${quantity}x ${product.name}.`);
    closeReceiptModal();
  };

  const closeNFeModal = () => {
    setIsNFeModalOpen(false);
    setNfeData(null);
    setError(null);
    if(fileInputRef.current) fileInputRef.current.value = "";
  }

  const openOutModal = (product: Product) => {
    setSelectedProduct(product);
    setOutQuantity(1);
    setOutEmployeeId(employees.length > 0 ? employees[0].id : '');
    setOutWorkOrderId('');
    setIsOutModalOpen(true);
  };

  const openProductModal = (product: Product | null) => {
    setCurrentProduct(product ? {...product} : { id: '', name: '', quantity: 0, unit_price: 0, min_stock: 10 });
    setIsProductModalOpen(true);
  };

  const closeProductModal = () => {
    setCurrentProduct(null);
    setIsProductModalOpen(false);
  };

  const openPriceHistoryModal = (product: Product) => {
    setSelectedProduct(product);
    setIsPriceHistoryModalOpen(true);
  };

  const closePriceHistoryModal = () => {
    setIsPriceHistoryModalOpen(false);
    setSelectedProduct(null);
  };

  const openReceiptModal = () => {
    setReceiptData({ productId: products.length > 0 ? products[0].id : '', quantity: 1, unitPrice: '', photo: '', photoName: '' });
    setIsReceiptModalOpen(true);
  }

  const closeReceiptModal = () => {
    setIsReceiptModalOpen(false);
  }

  const handleScan = (code: string) => {
      setSearchTerm(code);
      addToast(`Código ${code} escaneado!`, 'success');
      setIsScannerOpen(false);
  };

  const handleStockOut = async () => {
    const quantity = Number(outQuantity);
    if (!selectedProduct || quantity <= 0 || quantity > selectedProduct.quantity) {
      addToast("Quantidade de saída inválida.", 'error');
      return;
    }
    if (!outEmployeeId) {
        addToast("Por favor, selecione um funcionário.", 'error');
        return;
    }

    const originalProduct = products.find(p => p.id === selectedProduct.id);
    if (!originalProduct) return;

    const newQuantity = originalProduct.quantity - quantity;
    setProducts(prev => prev.map(p => p.id === originalProduct.id ? {...p, quantity: newQuantity} : p));

    const { error } = await supabase
        .from('products')
        .update({ quantity: newQuantity })
        .eq('id', selectedProduct.id);

    if (error) {
        addToast(`Erro ao atualizar estoque: ${error.message}`, 'error');
        setProducts(prev => prev.map(p => p.id === originalProduct.id ? originalProduct : p));
        return;
    }

    const employee = employees.find(e => e.id === outEmployeeId);
    const workOrder = workOrders.find(wo => wo.id === outWorkOrderId);

    const reason = workOrder 
        ? `para OS "${workOrder.title}" por ${employee?.name}`
        : `Uso geral por ${employee?.name}`;

    await addStockMovement({
      product_id: selectedProduct.id,
      product_name: selectedProduct.name,
      type: 'out',
      quantity: quantity,
      reason: reason,
      employee_id: outEmployeeId,
      employee_name: employee ? employee.name : undefined,
      work_order_id: outWorkOrderId || undefined,
    });

    addActivityLog(`registrou saída de ${quantity}x ${selectedProduct.name}.`);
    addToast('Saída de estoque registrada com sucesso!', 'success');

    // Check for low stock after outflow
    checkLowStock(originalProduct, newQuantity);

    setIsOutModalOpen(false);
    setSelectedProduct(null);
  };

  const productPriceHistory = useMemo(() => {
    if (!selectedProduct) return [];
    return priceHistory
      .filter(h => h.product_id === selectedProduct.id)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [priceHistory, selectedProduct]);

  const columns = [
    { header: 'Código', accessor: 'id' as const, sortable: true },
    { header: 'Nome', accessor: 'name' as const, sortable: true },
    { header: 'Quantidade', accessor: 'quantity' as const, sortable: true },
    { header: 'Preço Unitário', accessor: (item: Product) => (currentUser.role !== 'stockist' ? item.unit_price.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }) : '***'), sortable: currentUser.role !== 'stockist', sortKey: 'unit_price' as const},
    { header: 'Valor Total', accessor: (item: Product) => (currentUser.role !== 'stockist' ? ((Number(item.unit_price) || 0) * (Number(item.quantity) || 0)).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }) : '***'), sortable: false },
  ];

  const formInputClass = "mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-primary focus:border-primary sm:text-sm dark:bg-gray-700 dark:border-gray-600 dark:text-gray-200";

  return (
