              <span className="font-bold">{h.price.toLocaleString('pt-BR', {style: 'currency', currency: 'BRL'})}</span> em <span className="text-sm text-gray-500">{new Date(h.date).toLocaleDateString('pt-BR')}</span>
            </li>
