import { serve } from "https://deno.land/std@0.168.0/http/server.ts"

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const { message, type } = await req.json()

    // Configurações do Telegram (devem ser setadas no Supabase CLI: supabase secrets set TELEGRAM_BOT_TOKEN=... TELEGRAM_CHAT_ID=...)
    // Alternativamente, pode ser usado Evolution API ou Twilio para WhatsApp.
    const botToken = Deno.env.get('TELEGRAM_BOT_TOKEN')
    const chatId = Deno.env.get('TELEGRAM_CHAT_ID')

    if (!botToken || !chatId) {
      console.warn("Chaves de notificação externa (TELEGRAM_BOT_TOKEN ou TELEGRAM_CHAT_ID) não configuradas.")
      return new Response(JSON.stringify({ success: false, info: 'Missing credentials' }), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 200,
      })
    }

    // Envio para o Telegram
    const url = `https://api.telegram.org/bot${botToken}/sendMessage`
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: chatId,
        text: message,
        parse_mode: 'Markdown'
      })
    })

    const result = await response.json()

    return new Response(JSON.stringify({ success: result.ok, result }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 200,
    })

  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 400,
    })
  }
})

