import { Database } from '../types/supabase';

/**
 * World-class initialization of the Supabase client.
 * We prioritize process.env as it is the standard for environment variable injection in this runtime.
 */
const supabaseUrl = process.env.VITE_SUPABASE_URL || '';
const supabaseKey = process.env.VITE_SUPABASE_ANON_KEY || '';

// Export a single, constant instance to be used throughout the app
export const supabase = createClient<Database>(
    supabaseUrl, 
    supabaseKey
);

// Helper function to ensure compatibility with any existing components calling it
export const createSupabaseClient = () => supabase;

import { createClient, SupabaseClient } from '@supabase/supabase-js';
import { Database } from '../types/supabase';

/**
 * Busca variáveis de ambiente de forma robusta em diferentes contextos (Vite/Node).
 */
const getEnv = (name: string): string => {
  const env = (typeof process !== 'undefined' && process.env ? process.env : {}) as Record<string, string | undefined>;
  const metaEnv = (typeof import.meta !== 'undefined' && (import.meta as any).env ? (import.meta as any).env : {}) as Record<string, string | undefined>;

  return env[name] || metaEnv[name] || env[`VITE_${name}`] || metaEnv[`VITE_${name}`] || '';
};

const url = getEnv('SUPABASE_URL');
const key = getEnv('SUPABASE_ANON_KEY');

// Só cria o cliente se tivermos os dados. 
// Caso contrário, criamos um objeto que lança erro explicativo em português ao ser usado.
export const supabase = (url && key) 
  ? createClient<Database>(url, key)
  : new Proxy({} as SupabaseClient<Database>, {
      get: (target, prop) => {
        // Se tentar acessar o auth ou o from sem as chaves, lança o erro em português
        if (prop === 'auth' || prop === 'from' || prop === 'channel') {
           throw new Error('Erro: As chaves do Supabase (VITE_SUPABASE_URL e VITE_SUPABASE_ANON_KEY) não foram encontradas no ambiente. Configure-as no painel do seu projeto.');
        }
        return (target as any)[prop];
      }
    });

export const createSupabaseClient = () => supabase;

import React, { useState, useCallback, useEffect } from 'react';
import { supabase } from './services/supabaseClient';
import { SupabaseProvider, useSupabase } from './contexts/SupabaseContext';
import type { Session } from '@supabase/supabase-js';

import { Sidebar } from './components/shared/Sidebar';
import { Header } from './components/shared/Header';
import { Dashboard } from './components/Dashboard';
import { StockControl } from './components/StockControl';
import { Suppliers } from './components/Suppliers';
import { Clients } from './components/Clients';
import { Employees } from './components/Employees';
import { Users } from './components/Users';
import { Assets } from './components/Assets';
import { Categories } from './components/Categories';
import { Reports } from './components/Reports';
import { CarParts } from './components/CarParts';
import { Quotes } from './components/Quotes';
import { Login } from './components/Login';
import { NFControl } from './components/NFControl';
import { WorkOrders } from './components/WorkOrders';
import { PurchaseOrders } from './components/PurchaseOrders';
import { ActivityLog } from './components/ActivityLog';
import { User, AppNotification, ToastMessage } from './types';
import { ToastContainer } from './components/shared/ToastContainer';
import ConfirmationModal from './components/shared/ConfirmationModal';

type Page = 'dashboard' | 'stock' | 'carParts' | 'suppliers' | 'clients' | 'employees' | 'users' | 'assets' | 'categories' | 'reports' | 'quotes' | 'nfcontrol' | 'workorders' | 'purchaseorders' | 'activitylog';
type Theme = 'light' | 'dark';

const AppContent: React.FC = () => {
  const supabase = useSupabase();

  const [session, setSession] = useState<Session | null>(null);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentPage, setCurrentPage] = useState<Page>('dashboard');
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [theme, setTheme] = useState<Theme>('light');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isProfileLoading, setIsProfileLoading] = useState(false);
  const [dbSetupRequired, setDbSetupRequired] = useState(false);
  const [configError, setConfigError] = useState<string | null>(null);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [confirmation, setConfirmation] = useState<{
    isOpen: boolean;
    message: string;
    onConfirm: () => void;
  }>({ isOpen: false, message: '', onConfirm: () => {} });

  const addToast = useCallback((message: string, type: ToastMessage['type'] = 'info') => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts(currentToasts => currentToasts.filter(toast => toast.id !== id));
    }, 4000);
  }, []);

  const showConfirmation = useCallback((message: string, onConfirm: () => void) => {
    setConfirmation({ isOpen: true, message, onConfirm: () => {
        onConfirm();
        setConfirmation({ isOpen: false, message: '', onConfirm: () => {} });
    }});
  }, []);

  const closeConfirmation = () => setConfirmation({ isOpen: false, message: '', onConfirm: () => {} });

  useEffect(() => {
    const initSession = async () => {
        try {
            // Verifica se o supabase está funcional
            if (!supabase || typeof supabase.auth === 'undefined') {
                setConfigError('As chaves do Supabase não estão configuradas corretamente no ambiente do projeto.');
                return;
            }

            const { data: { session }, error } = await supabase.auth.getSession();
            if (error) throw error;
            setSession(session);
        } catch (e: any) {
            console.error("Erro na inicialização da sessão:", e);
            if (e.message.includes('VITE_SUPABASE_URL')) {
                setConfigError('Configuração ausente: Certifique-se de conectar seu projeto ao Supabase.');
            }
        }
    };
    initSession();

    if (supabase && supabase.auth) {
        const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
            setSession(session);
            if (event === 'SIGNED_OUT') setCurrentUser(null);
        });
        return () => subscription.unsubscribe();
    }
  }, [supabase]);

  useEffect(() => {
    const fetchUserProfile = async () => {
      if (session?.user && supabase && supabase.from) {
        setIsProfileLoading(true);
        try {
            const { data: checkData, error: checkError } = await supabase.from('profiles').select('id').limit(1);

            if (checkError && checkError.code === '42P01') { 
                setDbSetupRequired(true);
                setIsProfileLoading(false);
                return;
            }

            const { data, error } = await supabase
              .from('profiles')
              .select('*')
              .eq('id', session.user.id)
              .single();

            if (data) {
              setCurrentUser({
                id: data.id,
                name: data.full_name,
                email: session.user.email!,
                role: data.role as User['role'],
                organization_id: data.organization_id || undefined,
              });
            } else if (error && error.code === 'PGRST116') {
                const { data: newOrg } = await supabase.from('organizations').insert({ name: 'Minha Empresa' }).select().single();
                if (newOrg) {
                    const { data: newProfile } = await supabase.from('profiles').insert({
                        id: session.user.id,
                        full_name: session.user.email?.split('@')[0] || 'Usuário',
                        role: 'admin',
                        organization_id: newOrg.id
                    }).select().single();
                    if(newProfile) {
                        setCurrentUser({
                            id: newProfile.id,
                            name: newProfile.full_name,
                            email: session.user.email!,
                            role: 'admin',
                            organization_id: newOrg.id,
                        });
                    }
                }
            }
        } catch (e: any) {
            console.error("Erro ao carregar perfil:", e);
        } finally {
            setIsProfileLoading(false);
        }
      }
    };
    fetchUserProfile();
  }, [session, supabase]);

  useEffect(() => {
    if (!currentUser || !supabase || !supabase.from) return;
    const fetchNotifications = async () => {
        const { data } = await supabase.from('notifications').select('*').order('created_at', { ascending: false }).limit(20);
        if (data) setNotifications(data.map(n => ({ id: n.id, message: n.message, read: n.read, createdAt: n.created_at })));
    };
    fetchNotifications();
  }, [currentUser, supabase]);

  const handleLogout = async () => {
    if (supabase && supabase.auth) await supabase.auth.signOut();
  };

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as Theme | null;
    setTheme(savedTheme || 'light');
  }, []);

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove('light', 'dark');
    root.classList.add(theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const renderPage = () => {
    if (!currentUser) return null;
    const commonProps = { addToast, showConfirmation, currentUser, addActivityLog: (a: string) => console.log(a) };
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'stock': return <StockControl {...commonProps} />;
      case 'carParts': return <CarParts {...commonProps} />;
      case 'suppliers': return <Suppliers {...commonProps} />;
      case 'clients': return <Clients {...commonProps} />;
      case 'employees': return <Employees {...commonProps} />;
      case 'users': return <Users {...commonProps} />;
      case 'assets': return <Assets {...commonProps} />;
      case 'categories': return <Categories {...commonProps} />;
      case 'nfcontrol': return <NFControl />;
      case 'reports': return <Reports />;
      case 'quotes': return <Quotes {...commonProps} />;
      case 'workorders': return <WorkOrders {...commonProps} />;
      case 'purchaseorders': return <PurchaseOrders {...commonProps} />;
      case 'activitylog': return <ActivityLog />;
      default: return <Dashboard />;
    }
  };

  if (configError) {
      return (
          <div className="flex h-screen items-center justify-center bg-gray-900 text-white p-6">
              <div className="bg-gray-800 p-8 rounded-xl shadow-2xl border border-red-500 max-w-md text-center">
                  <svg className="w-16 h-16 text-red-500 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                  <h2 className="text-xl font-bold mb-2">Erro de Configuração</h2>
                  <p className="text-gray-400 mb-6">{configError}</p>
                  <p className="text-sm text-gray-500 italic">Por favor, verifique as variáveis de ambiente VITE_SUPABASE_URL e VITE_SUPABASE_ANON_KEY.</p>
              </div>
          </div>
      );
  }

  if (!session) return <Login />;

  if (dbSetupRequired) {
      return (
          <div className="flex min-h-screen bg-gray-900 text-white p-4">
              <div className="m-auto w-full max-w-4xl bg-gray-800 rounded-lg shadow-2xl border border-gray-700 p-8">
                  <h2 className="text-2xl font-bold text-red-500 mb-4">Banco de Dados não Inicializado</h2>
                  <p className="mb-6">Você precisa executar o script SQL no seu painel do Supabase para criar as tabelas necessárias antes de continuar.</p>
                  <button onClick={() => window.location.reload()} className="bg-green-600 px-6 py-2 rounded font-bold hover:bg-green-700 transition">Já executei o SQL, recarregar</button>
              </div>
          </div>
      );
  }

  if (isProfileLoading) {
      return <div className="flex h-screen items-center justify-center bg-gray-900 text-white animate-pulse">Carregando Perfil...</div>;
  }

  return (
    <div className="flex h-screen bg-gray-100 dark:bg-gray-900">
      <Sidebar currentPage={currentPage} setCurrentPage={setCurrentPage} isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} currentUser={currentUser} />
      <div className="flex-1 flex flex-col overflow-hidden">
        <Header theme={theme} setTheme={setTheme} toggleSidebar={() => setIsSidebarOpen(prev => !prev)} notifications={notifications} setNotifications={setNotifications} handleLogout={handleLogout} currentUser={currentUser} />
        <main className="flex-1 overflow-y-auto p-4 sm:p-6 md:p-8">{renderPage()}</main>
      </div>
      <ToastContainer toasts={toasts} />
      <ConfirmationModal isOpen={confirmation.isOpen} onClose={closeConfirmation} onConfirm={confirmation.onConfirm} message={confirmation.message} />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <SupabaseProvider>
      <AppContent />
    </SupabaseProvider>
  );
};

export default App;
